import{_ as a,c as s,o as n,ag as l}from"./chunks/framework.z0p7P-Mv.js";const h=JSON.parse('{"title":"pod的创建流程","description":"","frontmatter":{},"headers":[],"relativePath":"zh/k8s/InterviewQuestions/Procedure_of_creating_pods.md","filePath":"zh/k8s/InterviewQuestions/Procedure_of_creating_pods.md"}'),o={name:"zh/k8s/InterviewQuestions/Procedure_of_creating_pods.md"};function p(t,e,r,i,c,d){return n(),s("div",null,[...e[0]||(e[0]=[l(`<h1 id="pod的创建流程" tabindex="-1">pod的创建流程 <a class="header-anchor" href="#pod的创建流程" aria-label="Permalink to &quot;pod的创建流程&quot;">​</a></h1><h2 id="整体流程" tabindex="-1">整体流程 <a class="header-anchor" href="#整体流程" aria-label="Permalink to &quot;整体流程&quot;">​</a></h2><p>1:执行 kubectl create -f nginx-deploy yaml → kubectl 向 kube-apiserver 发起创建请求；</p><p>2:kube-apiserver 完成「认证/授权」后，将Deployment 的「期望状态」(比如3个副本）写入etcd，并返回创建成功；</p><p>3:kube-controler-manager 中的 Deployment 控制器，通过apiserver 发现新的 Deployment，自动创建对应的 ReplicaSet;</p><p>4:eplicaSet 控制器发现「期望3个Pod，实际0个」，通过 apiserver 创建3个Pod 的资源对象，写入etcd:</p><p>5:kube-scheduler 监听 apiserver，发现3个[待调度的 Pod」，为每个Pod 筛选并打分，选出最合 适的 Node 节点，将调度结果(Pod 绑定到哪个Node）更新到etcd；</p><p>6:对应 Node节点上的 kubelet，通过apiserver 发现「自己被分配了Pod」，调用容器运行时（Docker/containerd)创建 Pod，Pod 启动成功后，kubelet 将 Pod的「实际运行状态」上报给 apiserver，apiserver 更新到 etcd; pn</p><p>7: kube-proxy 监控到 Pod 创建后，更新本地的 iptables/ipvs 规则，让 Service 可以转发流量到新Pod;</p><h2 id="整体逻辑-三层架构" tabindex="-1">整体逻辑（三层架构） <a class="header-anchor" href="#整体逻辑-三层架构" aria-label="Permalink to &quot;整体逻辑（三层架构）&quot;">​</a></h2><h3 id="请求层-kubeclt发起请求、apiserver接收请求" tabindex="-1"><strong>请求层</strong>（kubeclt发起请求、apiserver接收请求） <a class="header-anchor" href="#请求层-kubeclt发起请求、apiserver接收请求" aria-label="Permalink to &quot;**请求层**（kubeclt发起请求、apiserver接收请求）&quot;">​</a></h3><ul><li><p>执行 kubectl create -f nginx-deploy yaml → kubectl 向 kube-apiserver 发起创建请求；</p></li><li><p>kube-apiserver 完成「认证/授权」后，将Deployment 的「期望状态」(比如3个副本）写入etcd，并返回创建成功；</p></li><li><p><code>kubectl</code> → <code>kube-apiserver</code></p></li><li><p>apiserver 负责：</p><ul><li>认证、授权</li><li>写入期望状态(比如3个副本）到 <code>etcd</code></li></ul></li></ul><blockquote><p>记忆口诀：<strong>“kubectl喊，apiserver写etcd”</strong></p></blockquote><hr><h3 id="控制器层-实现期望状态" tabindex="-1"><strong>控制器层</strong>（实现期望状态） <a class="header-anchor" href="#控制器层-实现期望状态" aria-label="Permalink to &quot;**控制器层**（实现期望状态）&quot;">​</a></h3><ul><li><p>kube-controler-manager 中的 Deployment 控制器，通过apiserver 发现新的 Deployment，自动创建对应的 ReplicaSet;</p></li><li><p>ReplicaSet 控制器发现「期望3个Pod，实际0个」，通过 apiserver 创建3个Pod 的资源对象，写入etcd:</p></li><li><p><code>Deployment Controller</code> → 发现新的 Deployment → 创建 <code>ReplicaSet</code></p></li><li><p><code>ReplicaSet Controller</code> → 检查实际 Pod 数量 vs 期望副本 → 创建 Pod 对象</p></li></ul><blockquote><p>记忆口诀：<strong>“Deployment催，ReplicaSet补”</strong></p></blockquote><hr><h3 id="调度-节点执行层" tabindex="-1"><strong>调度 &amp; 节点执行层</strong> <a class="header-anchor" href="#调度-节点执行层" aria-label="Permalink to &quot;**调度 &amp; 节点执行层**&quot;">​</a></h3><ul><li><code>kube-scheduler</code> → 给 Pod 选 Node → 更新绑定信息</li><li><code>kubelet</code> → 在 Node 上创建 Pod → 上报状态</li><li><code>kube-proxy</code> → 更新本地网络规则</li></ul><blockquote><p>记忆口诀：<strong>“Scheduler选，Kubelet建，Proxy通”</strong></p></blockquote><h2 id="自愈流程" tabindex="-1">自愈流程 <a class="header-anchor" href="#自愈流程" aria-label="Permalink to &quot;自愈流程&quot;">​</a></h2><p>如果某个Pod宕机</p><p>→ ReplicaSet控制器发现「实际2个Pod+期望 3个」</p><p>→自动创建新Pod</p><p>→ scheduler 重新调度</p><p>→ kubelet 创建 Pod，完成自愈。</p><hr><h2 id="自愈逻辑" tabindex="-1">自愈逻辑 <a class="header-anchor" href="#自愈逻辑" aria-label="Permalink to &quot;自愈逻辑&quot;">​</a></h2><ul><li>Pod 宕机 → ReplicaSet 发现不够 → 重新创建 → Scheduler 调度 → Kubelet 启动</li><li>本质就是：<strong>控制器循环 + 调度 + 节点执行</strong></li></ul><blockquote><p>记忆口诀：<strong>“失踪补齐，调度执行”</strong></p></blockquote><hr><h2 id="pod-创建流程图" tabindex="-1">Pod 创建流程图 <a class="header-anchor" href="#pod-创建流程图" aria-label="Permalink to &quot;Pod 创建流程图&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>kubectl create</span></span>
<span class="line"><span>      │</span></span>
<span class="line"><span>      ▼</span></span>
<span class="line"><span>kube-apiserver (写期望状态etcd)</span></span>
<span class="line"><span>      │</span></span>
<span class="line"><span>      ▼</span></span>
<span class="line"><span>Deployment Controller → ReplicaSet Controller</span></span>
<span class="line"><span>      │</span></span>
<span class="line"><span>      ▼</span></span>
<span class="line"><span>ReplicaSet 创建 Pod 对象 (写etcd)</span></span>
<span class="line"><span>      │</span></span>
<span class="line"><span>      ▼</span></span>
<span class="line"><span>kube-scheduler 选择 Node</span></span>
<span class="line"><span>      │</span></span>
<span class="line"><span>      ▼</span></span>
<span class="line"><span>kubelet 在 Node 上创建 Pod → 状态上报</span></span>
<span class="line"><span>      │</span></span>
<span class="line"><span>      ▼</span></span>
<span class="line"><span>kube-proxy 更新网络</span></span></code></pre></div><ul><li><strong>关键点</strong>：Deployment → ReplicaSet → Pod → Scheduler → Kubelet → Proxy</li><li><strong>自愈</strong>：ReplicaSet 检测 Pod 不够 → 重新触发调度 → Kubelet 创建</li></ul><hr><h2 id="助记口诀" tabindex="-1">助记口诀 <a class="header-anchor" href="#助记口诀" aria-label="Permalink to &quot;助记口诀&quot;">​</a></h2><blockquote><p><strong>kubectl喊 → apiserver写 → Deployment催 → ReplicaSet补 → Scheduler选 → Kubelet建 → Proxy通 → Pod活</strong></p></blockquote>`,38)])])}const b=a(o,[["render",p]]);export{h as __pageData,b as default};
